/*******************************************************************************************************
 PARAMETRO SPESSORI + ALTEZZA/TIPO PRODOTTO PER DETERMINARE IL NUMERO DI PANNELLI PER PACCO ALLA PRESSA
********************************************************************************************************
********************************************************************************************************/

delete from para where codice like 'HPR%'


delete from para where codice like 'SHT%'














select codice,descri,libera,italiano,note,desiva,* from para where codice like 'HPR%'
select codice,descri,libera,italiano,note,desiva,* from para where codice like 'SHT%'
